def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete into a fluent, combined sentence."""
    if not triples:
        return ""

    # organise triples by subject for easy lookup
    subj_map: dict[str, list[tuple[str, str]]] = {}
    for t in triples:
        subj_map.setdefault(t.subject, []).append((t.predicate, t.object))

    # helper to render a single (subject, predicate, object) with possible
    # augmentation using information from other triples
    def render(s: str, p: str, o: str) -> str:
        # basic mappings with refined phrasing
        if p == "birthDate":
            # convert ISO date to a readable format if possible
            try:
                from datetime import datetime
                d = datetime.strptime(o, "%Y-%m-%d")
                o_fmt = d.strftime("%-d %B %Y")
            except Exception:
                o_fmt = o
            base = f"{s} was born on {o_fmt}"
        elif p == "birthYear":
            base = f"{s} was born in {o}"
        elif p == "birthPlace":
            base = f"{s} was born in {o}"
        elif p == "height":
            base = f"{s} is {o} metres tall"
        elif p == "weight":
            # Clean up possible parenthetical units and ensure a readable unit
            cleaned = o.replace('(', '').replace(')', '').strip()
            # If a unit like kg or kilogram is already present, keep it; otherwise append kg
            if any(u in cleaned.lower() for u in ["kg", "kilogram", "kilograms"]):
                weight_str = cleaned
            else:
                weight_str = f"{cleaned} kg"
            base = f"{s} weighs {weight_str}"
        elif p == "position":
            clean_o = o.split('(')[0].strip()
            article = "an" if clean_o[0].lower() in "aeiou" else "a"
            base = f"{s} plays as {article} {clean_o}"
        elif p == "draftTeam":
            base = f"{s}'s draft team is {o}"
        elif p == "activeYearsStartYear":
            base = f"{s} started playing in {o}"
        elif p in ("club", "currentclub"):
            # Base phrasing for club affiliation
            base = f"{s} plays for {o}"
            # Enrich with chairman information if the club has a chairman
            if o in subj_map:
                for sp, so in subj_map[o]:
                    if sp == "chairman":
                        base += f", whose chairman is {so}"
                        break
        elif p == "formerTeam":
            base = f"{s} formerly played for {o}"
        elif p == "league":
            base = f"{s} competes in the {o}"
        elif p == "manager":
            base = f"{o} is the manager of {s}"
        elif p == "coach":
            base = f"{o} is the coach of {s}"
        elif p == "draftYear":
            base = f"{s} was drafted in {o}"
        elif p == "draftRound":
            base = f"{s} was selected in round {o}"
        elif p == "draftPick":
            base = f"{s} was the {o}th pick"
        elif p == "playerNumber":
            base = f"{s} wears number {o}"
        elif p == "currentteam":
            base = f"{s} currently plays for {o}"
        elif p == "debutTeam":
            # Prefer phrasing that can be enriched with the team's city if known
            base = f"{s}'s debut team was the {o}"
            # augment with city of the team if available
            if o in subj_map:
                for sp, so in subj_map[o]:
                    if sp == "city":
                        base += f" who play in {so}"
                        break
        elif p == "leader":
            base = f"{o} is the leader of {s}"
        elif p == "deathPlace":
            base = f"{s} died in {o}"
        elif p == "isPartOf":
            base = f"{s} is part of {o}"
        elif p == "country":
            base = f"{s} is in {o}"
        elif p == "mostChampions":
            base = f"{o} have won the {s} the most times"
        elif p == "ethnicGroup":
            base = f"{o} are an ethnic group in {s}"
        elif p == "language":
            # natural phrasing for language of a country
            base = f"The {o} is spoken in {s}"
        elif p == "anthem":
            base = f"The anthem of {s} is {o}"
        elif p == "currency":
            base = f"The currency of {s} is {o}"
        elif p == "demonym":
            base = f"The demonym for {s} is {o}"
        elif p == "officialLanguage":
            base = f"The official language of {s} is {o}"
        elif p == "ground":
            # Use more natural phrasing for stadium/ground relationships
            base = f"{o} is the home ground of {s}"
        elif p == "city":
            base = f"{s} is based in {o}"
        elif p == "chairman":
            base = f"The chairman of {s} is {o}"
        elif p == "youthclub":
            base = f"{s} played for the youth team of {o}"
        else:
            base = f"{s} {p} {o}"

        # augment with secondary information (e.g., club's manager, ground's city)
        if p in ("club", "currentclub") and o in subj_map:
            for sp, so in subj_map[o]:
                if sp == "manager":
                    base += f", which is managed by {so}"
                    break
        if p == "ground" and o in subj_map:
            for sp, so in subj_map[o]:
                if sp == "city":
                    base += f", located in {so}"
                    break
        # additional augmentation using object's own predicates (owner, city, country, league, manager, position)
        if o in subj_map:
            augment_map = {
                "owner": "owned by",
                "city": "based in",
                "country": "in",
                "league": "in the",
                "manager": "managed by",
                "ground": "located at",
                "position": "playing as"
            }
            clauses = []
            for sp, so in subj_map[o]:
                if sp in augment_map:
                    clauses.append(f"which is {augment_map[sp]} {so}")
            if clauses:
                base += ", " + " and ".join(clauses)
        return base

    # Remove redundant birthYear when birthDate is present for the same subject
    cleaned_phrases = []
    for s, pred_objs in subj_map.items():
        # filter out birthYear if birthDate also exists
        preds = [p for p, _ in pred_objs]
        if "birthDate" in preds:
            pred_objs = [(p, o) for p, o in pred_objs if p != "birthYear"]
        cleaned_phrases.append((s, pred_objs))

    # build phrases per subject, merging multiple predicates of the same subject,
    # and aggregating multiple values for the same predicate (e.g., several clubs)
    phrases = []
    for s, pred_objs in subj_map.items():
        # aggregate objects per predicate
        agg: dict[str, list[str]] = {}
        for p, o in pred_objs:
            agg.setdefault(p, []).append(o)

        sub_phrases: list[str] = []

        # special handling for clubs and current clubs
        clubs = agg.get("club", [])
        current = agg.get("currentclub", [])
        # combine current club with clubs list, but keep ordering: current first if exists
        if current:
            # current club is present
            cur_club = current[0]
            sub_phrases.append(f"{s} currently plays for {cur_club}")
            # remove it from clubs if duplicated
            clubs = [c for c in clubs if c != cur_club]
        if clubs:
            # past clubs
            if len(clubs) == 1:
                past_phrase = f"{s} has played for {clubs[0]}"
            else:
                past_clubs = ", ".join(clubs[:-1]) + f" and {clubs[-1]}"
                past_phrase = f"{s} has played for {past_clubs}"
            # add manager info if available for each club
            manager_parts = []
            for club in clubs:
                if club in subj_map:
                    for sp, so in subj_map[club]:
                        if sp == "manager":
                            manager_parts.append(f"{club} is managed by {so}")
            if manager_parts:
                past_phrase += "; " + "; ".join(manager_parts)
            sub_phrases.append(past_phrase)

        # handle other predicates
        for p, objs in agg.items():
            if p in ("club", "currentclub"):
                continue  # already processed
            if len(objs) == 1:
                sub_phrases.append(render(s, p, objs[0]))
            else:
                rendered = [render(s, p, o) for o in objs]
                combined = ", ".join(rendered)
                sub_phrases.append(combined)

        # combine sub_phrases for this subject
        if len(sub_phrases) == 1:
            phrases.append(sub_phrases[0])
        else:
            combined = ", ".join(sub_phrases[:-1]) + f", and {sub_phrases[-1]}"
            phrases.append(combined)

    # build phrases per subject, merging multiple predicates of the same subject,
    # and aggregating multiple values for the same predicate (e.g., several clubs)
    phrases = []
    for s, pred_objs in subj_map.items():
        # aggregate objects per predicate
        agg: dict[str, list[str]] = {}
        for p, o in pred_objs:
            agg.setdefault(p, []).append(o)

        sub_phrases: list[str] = []

        for p, objs in agg.items():
            # handle aggregation for club/currentclub predicates
            if p in ("club", "currentclub"):
                if len(objs) == 1:
                    base = f"{s} plays for {objs[0]}"
                else:
                    # join with commas and 'and' for the last item
                    clubs = ", ".join(objs[:-1]) + f" and {objs[-1]}"
                    base = f"{s} plays for {clubs}"
                # add position/league info if available for each club
                extra_parts = []
                for club in objs:
                    if club in subj_map:
                        for sp, so in subj_map[club]:
                            if sp in ("position", "league"):
                                extra_parts.append(f"{club} competes in the {so}")
                if extra_parts:
                    base += "; " + "; ".join(extra_parts)
                sub_phrases.append(base)
                continue

            # handle other predicates with possible multiple objects
            if len(objs) == 1:
                sub_phrases.append(render(s, p, objs[0]))
            else:
                # render each and join with commas
                rendered = [render(s, p, o) for o in objs]
                combined = ", ".join(rendered)
                sub_phrases.append(combined)

        # combine sub_phrases for this subject
        if len(sub_phrases) == 1:
            phrases.append(sub_phrases[0])
        else:
            combined = ", ".join(sub_phrases[:-1]) + f", and {sub_phrases[-1]}"
            phrases.append(combined)

    # finally join all subject‑level phrases into one sentence
    if len(phrases) == 1:
        return phrases[0] + "."
    else:
        return "; ".join(phrases) + "."

